mapper.select:
SELECT * from (
WITH duplicate_keys AS ( SELECT '医院' as table_name, keyid, hs_code FROM base_org_hos_clean WHERE status = 1 AND hs_code <> '' GROUP BY keyid, hs_code HAVING COUNT(*) > 1
UNION ALL
SELECT '商业' as table_name, keyid, hs_code FROM base_org_company WHERE status = 1 AND hs_code <> '' GROUP BY keyid, hs_code HAVING COUNT(*) > 1
UNION ALL
SELECT '药店' as table_name, keyid, hs_code FROM base_org_drug_store WHERE status = 1 AND hs_code <> '' GROUP BY keyid, hs_code HAVING COUNT(*) > 1 )
SELECT '医院' as org_type, h.data_id, h.original_name, h.data_code, h.keyid, h.province, h.name, h.hs_code, h.addtime, h.name_history FROM base_org_hos_clean h INNER JOIN duplicate_keys d ON d.table_name = '医院' AND h.keyid = d.keyid AND h.hs_code = d.hs_code WHERE h.status = 1 AND h.hs_code <> ''
UNION ALL
SELECT '商业' as org_type, c.data_id, c.original_name, c.data_code, c.keyid, c.province, c.name, c.hs_code, c.addtime, c.name_history FROM base_org_company c INNER JOIN duplicate_keys d ON d.table_name = '商业' AND c.keyid = d.keyid AND c.hs_code = d.hs_code WHERE c.status = 1 AND c.hs_code <> ''
UNION ALL
SELECT '药店' as org_type, dg.data_id, dg.original_name, dg.data_code, dg.keyid, dg.province, dg.name, dg.hs_code, dg.addtime, dg.history_name FROM base_org_drug_store dg INNER JOIN duplicate_keys d ON d.table_name = '药店' AND dg.keyid = d.keyid AND dg.hs_code = d.hs_code WHERE dg.status = 1 AND dg.hs_code <> '' ) a
AND org_type = #{condition.orgType}
AND data_id = #{condition.dataId}
AND original_name = #{condition.originalName}
AND data_code = #{condition.dataCode}
AND province = #{condition.province}
AND name = #{condition.name}
AND hs_code = #{condition.hsCode}
AND keyid = #{condition.keyid}
ORDER BY a.keyid DESC

mapper.update:
WITH duplicate_data AS ( SELECT data_id FROM ( SELECT data_id, ROW_NUMBER() OVER(PARTITION BY keyid, hs_code ORDER BY addtime DESC) as rn FROM base_org_company WHERE status = 1 AND hs_code <> '' AND (keyid, hs_code) IN ( SELECT keyid, hs_code FROM base_org_company WHERE status = 1 AND hs_code <> '' GROUP BY keyid, hs_code HAVING COUNT(*) > 1 ) ) t WHERE rn <> 1 ) UPDATE base_org_company SET status = 5, remarks = CONCAT( COALESCE(remarks, ''), '重复数据', TO_CHAR(CURRENT_DATE, 'YYMMDD'), ';' ), updatetime = NOW() FROM duplicate_data d WHERE base_org_company.data_id = d.data_id;
UPDATE company SET status = 5, remarks = CONCAT( COALESCE(remarks, ''), '重复数据', TO_CHAR(CURRENT_DATE, 'YYMMDD'), ';' ), updatetime = NOW() WHERE status = 1 AND data_id IN (SELECT data_id FROM base_org_company WHERE status = 5);
WITH duplicate_data AS ( SELECT data_id FROM ( SELECT data_id, ROW_NUMBER() OVER(PARTITION BY keyid, hs_code ORDER BY addtime DESC) as rn FROM base_org_hos_clean WHERE status = 1 AND hs_code <> '' AND (keyid, hs_code) IN ( SELECT keyid, hs_code FROM base_org_hos_clean WHERE status = 1 AND hs_code <> '' GROUP BY keyid, hs_code HAVING COUNT(*) > 1 ) ) t WHERE rn <> 1 ) UPDATE base_org_hos_clean SET status = 5, remarks = CONCAT( COALESCE(remarks, ''), '重复数据', TO_CHAR(CURRENT_DATE, 'YYMMDD'), ';' ), updatetime = NOW() FROM duplicate_data d WHERE base_org_hos_clean.data_id = d.data_id;
UPDATE hos_clean SET status = 5, remarks = CONCAT( COALESCE(remarks, ''), '重复数据', TO_CHAR(CURRENT_DATE, 'YYMMDD'), ';' ), updatetime = NOW() WHERE status = 1 AND data_id IN (SELECT data_id FROM base_org_hos_clean WHERE status = 5);
WITH duplicate_data AS ( SELECT data_id FROM ( SELECT data_id, ROW_NUMBER() OVER(PARTITION BY keyid, hs_code ORDER BY addtime DESC) as rn FROM base_org_drug_store WHERE status = 1 AND hs_code <> '' AND (keyid, hs_code) IN ( SELECT keyid, hs_code FROM base_org_drug_store WHERE status = 1 AND hs_code <> '' GROUP BY keyid, hs_code HAVING COUNT(*) > 1 ) ) t WHERE rn <> 1 ) UPDATE base_org_drug_store SET status = 5, remarks = CONCAT( COALESCE(remarks, ''), '重复数据', TO_CHAR(CURRENT_DATE, 'YYMMDD'), ';' ), updatetime = NOW() FROM duplicate_data d WHERE base_org_drug_store.data_id = d.data_id;
UPDATE drug_store SET status = 5, remarks = CONCAT( COALESCE(remarks, ''), '重复数据', TO_CHAR(CURRENT_DATE, 'YYMMDD'), ';' ), updatetime = NOW() WHERE status = 1 AND data_id IN (SELECT data_id FROM base_org_drug_store WHERE status = 5);
UPDATE base_org_company t1 SET status = 1, updatetime = NOW() WHERE t1.status = 5 AND NOT EXISTS ( SELECT 1 FROM base_org_company t2 WHERE t2.status = 1 AND t2.hs_code <> '' AND t2.keyid = t1.keyid AND t2.hs_code = t1.hs_code );
UPDATE company t1 SET status = 1, updatetime = NOW() WHERE t1.status = 5 AND NOT EXISTS ( SELECT 1 FROM company t2 WHERE t2.status = 1 AND t2.hs_code <> '' AND t2.keyid = t1.keyid AND t2.hs_code = t1.hs_code );
UPDATE base_org_hos_clean t1 SET status = 1, updatetime = NOW() WHERE t1.status = 5 AND NOT EXISTS ( SELECT 1 FROM base_org_hos_clean t2 WHERE t2.status = 1 AND t2.hs_code <> '' AND t2.keyid = t1.keyid AND t2.hs_code = t1.hs_code );
UPDATE hos_clean t1 SET status = 1, updatetime = NOW() WHERE t1.status = 5 AND NOT EXISTS ( SELECT 1 FROM hos_clean t2 WHERE t2.status = 1 AND t2.hs_code <> '' AND t2.keyid = t1.keyid AND t2.hs_code = t1.hs_code );
UPDATE base_org_drug_store t1 SET status = 1, updatetime = NOW() WHERE t1.status = 5 AND NOT EXISTS ( SELECT 1 FROM base_org_drug_store t2 WHERE t2.status = 1 AND t2.hs_code <> '' AND t2.keyid = t1.keyid AND t2.hs_code = t1.hs_code );
UPDATE drug_store t1 SET status = 1, updatetime = NOW() WHERE t1.status = 5 AND NOT EXISTS ( SELECT 1 FROM drug_store t2 WHERE t2.status = 1 AND t2.hs_code <> '' AND t2.keyid = t1.keyid AND t2.hs_code = t1.hs_code );
